namespace BlazorNotifications.Services;

public record Notification(int Id, string Message, DateTime Timestamp);

public class NotificationService
{
    private int _nextId = 1;
    private readonly Lock _lock = new();

    private readonly List<Notification> _notifications = [];

    public NotificationService()
    {
        // Seed with initial fake data
        _notifications.Add(new Notification(_nextId++, "Welcome to the app!", DateTime.UtcNow.AddMinutes(-10)));
        _notifications.Add(new Notification(_nextId++, "Your profile was updated.", DateTime.UtcNow.AddMinutes(-5)));
        _notifications.Add(new Notification(_nextId++, "New feature available: Dark Mode.", DateTime.UtcNow.AddMinutes(-2)));
    }

    /// <summary>
    /// Returns all notifications currently available.
    /// </summary>
    public List<Notification> GetAll()
    {
        lock (_lock)
        {
            return [.. _notifications];
        }
    }

    /// <summary>
    /// Returns notifications added after the given ID (for polling).
    /// </summary>
    public List<Notification> GetSince(int lastSeenId)
    {
        lock (_lock)
        {
            return _notifications.Where(n => n.Id > lastSeenId).ToList();
        }
    }

    /// <summary>
    /// Simulates new notifications arriving over time.
    /// Called internally to generate fake data.
    /// </summary>
    public void SimulateNewNotification()
    {
        var messages = new[]
        {
            "Someone liked your post.",
            "You have a new follower.",
            "Server maintenance scheduled.",
            "Your export is ready.",
            "New comment on your article.",
            "Payment received successfully.",
            "Reminder: meeting in 15 minutes.",
        };

        lock (_lock)
        {
            var message = messages[_nextId % messages.Length];
            _notifications.Add(new Notification(_nextId++, message, DateTime.UtcNow));
        }
    }
}

namespace BlazorNotifications.Services;

/// <summary>
/// Background service that periodically adds fake notifications
/// so the polling page has something new to pick up.
/// </summary>
public class NotificationSimulatorHostedService(NotificationService notificationService) : BackgroundService
{
    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
    {
        while (!stoppingToken.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(7), stoppingToken);
            notificationService.SimulateNewNotification();
        }
    }
}

@page "/notifications"
@rendermode @(new InteractiveServerRenderMode(prerender: true))
@implements IDisposable
@inject BlazorNotifications.Services.NotificationService NotificationService

<PageTitle>Notifications</PageTitle>

<h1>Notifications <span class="badge bg-primary">@notifications.Count</span></h1>

@if (notifications.Count == 0)
{
    <p><em>No notifications yet.</em></p>
}
else
{
    <ul class="list-group">
        @foreach (var n in notifications.OrderByDescending(x => x.Timestamp))
        {
            <li class="list-group-item d-flex justify-content-between align-items-center">
                @n.Message
                <small class="text-muted">@n.Timestamp.ToString("HH:mm:ss")</small>
            </li>
        }
    </ul>
}

@code {
    private List<BlazorNotifications.Services.Notification> notifications = [];
    private CancellationTokenSource? _cts;
    private int _lastSeenId;

    protected override void OnInitialized()
    {
        // Load initial notifications during prerender AND interactive init.
        // On the interactive init this reuses the same service data,
        // avoiding a redundant fetch since the data is already rendered in HTML.
        notifications = NotificationService.GetAll();
        _lastSeenId = notifications.Count > 0 ? notifications.Max(n => n.Id) : 0;
    }

    protected override void OnAfterRender(bool firstRender)
    {
        if (firstRender)
        {
            // OnAfterRender only fires when the component is live and interactive
            // (never during static SSR prerender), so polling starts only when interactive.
            _cts = new CancellationTokenSource();
            _ = PollForNotificationsAsync(_cts.Token);
        }
    }

    private async Task PollForNotificationsAsync(CancellationToken cancellationToken)
    {
        while (!cancellationToken.IsCancellationRequested)
        {
            await Task.Delay(TimeSpan.FromSeconds(5), cancellationToken);

            var newItems = NotificationService.GetSince(_lastSeenId);
            if (newItems.Count > 0)
            {
                notifications.AddRange(newItems);
                _lastSeenId = newItems.Max(n => n.Id);
                await InvokeAsync(StateHasChanged);
            }
        }
    }

    public void Dispose()
    {
        _cts?.Cancel();
        _cts?.Dispose();
    }
}

