+namespace BlazorNotifications.Services;
+
+/// <summary>
+/// Background service that periodically adds fake notifications
+/// so the polling page has something new to pick up.
+/// </summary>
+public class NotificationSimulatorHostedService(NotificationService notificationService) : BackgroundService
+{
+    protected override async Task ExecuteAsync(CancellationToken stoppingToken)
+    {
+        while (!stoppingToken.IsCancellationRequested)
+        {
+            await Task.Delay(TimeSpan.FromSeconds(7), stoppingToken);
+            notificationService.SimulateNewNotification();
+        }
+    }
+}
